prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId ?origId .
  FILTER(STR(?origId) = "4ccc3fd711004f519782ac92e58f6ddd")
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?chName (COUNT(DISTINCT ?task) AS ?taskCount) (COUNT(DISTINCT ?gw) AS ?gatewayCount) (COUNT(DISTINCT ?evt) AS ?eventCount) (COUNT(DISTINCT ?flow) AS ?sequenceFlowCount)
WHERE {
  ?model a bboExt:Model .
  FILTER(STR(?model) = "https://www.teamingai-project.eu/kg/model/sid_2258986a_c790_4708_ae4e_8dc02b7d122d")
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?choreo bbo:name ?chName . }

  OPTIONAL { ?task a bboExt:ChoreographyTask . ?task tai:belongsTo ?choreo . }
  OPTIONAL { ?gw a ?gwType . FILTER(?gwType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway)) . ?gw tai:belongsTo ?choreo . }
  OPTIONAL { ?evt a ?evtType . FILTER(?evtType IN (bboExt:StartEvent, bboExt:IntermediateCatchEvent, bboExt:EndEvent)) . ?evt tai:belongsTo ?choreo . }
  OPTIONAL { ?edge a bbo:SequenceFlow . ?edge tai:belongsTo ?choreo . ?edge bbo:has_sourceRef ?s . ?edge bbo:has_targetRef ?t . ?s tai:belongsTo ?choreo . ?t tai:belongsTo ?choreo . }
}
GROUP BY ?choreo ?chName
ORDER BY DESC(?sequenceFlowCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?src ?srcName ?tgt ?tgtName ?isImmediate
       ?gwDir ?gwDefault ?gwInst
WHERE {
  ?model a bboExt:Model .
  FILTER(STR(?model) = "https://www.teamingai-project.eu/kg/model/sid_2258986a_c790_4708_ae4e_8dc02b7d122d")

  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?src ;
        bbo:has_targetRef ?tgt .
  ?src tai:belongsTo ?choreo .
  ?tgt tai:belongsTo ?choreo .
  OPTIONAL { ?edge bboExt:isImmediate ?isImmediate . }

  OPTIONAL {
    FILTER( EXISTS { ?src a bboExt:ExclusiveGateway } || EXISTS { ?src a bboExt:ParallelGateway } || EXISTS { ?src a bboExt:EventBasedGateway } )
    ?src a ?gwType .
    OPTIONAL { ?src bboExt:gatewayDirection ?gwDir . }
    OPTIONAL { ?src bboExt:default ?gwDefault . }
    OPTIONAL { ?src bboExt:instantiate ?gwInst . }
  }

  OPTIONAL { ?src bbo:name ?srcName . }
  OPTIONAL { ?tgt bbo:name ?tgtName . }
}
ORDER BY ?edge
LIMIT 25
